import{_ as e,o,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"底模是什么","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/base-model.md","filePath":"concepts/base-model.md","lastUpdated":1782223980000}'),t={name:"concepts/base-model.md"};function r(n,a,s,d,h,c){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="底模是什么" tabindex="-1">底模是什么 <a class="header-anchor" href="#底模是什么" aria-label="Permalink to &quot;底模是什么&quot;">​</a></h1><p>一句话：底模是 AI 绘画系统的核心生成模型，决定它“会画什么、擅长什么、默认风格是什么”。</p><h2 id="底模、checkpoint、base-model-的关系" tabindex="-1">底模、Checkpoint、Base Model 的关系 <a class="header-anchor" href="#底模、checkpoint、base-model-的关系" aria-label="Permalink to &quot;底模、Checkpoint、Base Model 的关系&quot;">​</a></h2><p>在不同教程里，你会看到几个相近的词：</p><ul><li>底模：中文习惯说法，指生成图片的核心模型。</li><li>Checkpoint：常见文件形式，通常是 <code>.safetensors</code> 或 <code>.ckpt</code>。</li><li>Base Model：训练或微调时的基础模型，也常用于说明 LoRA 兼容性。</li></ul><p>实际使用时，很多人说“换底模”，就是在 WebUI 或 ComfyUI 里换一个 checkpoint。</p><h2 id="为什么底模很重要" tabindex="-1">为什么底模很重要 <a class="header-anchor" href="#为什么底模很重要" aria-label="Permalink to &quot;为什么底模很重要&quot;">​</a></h2><p>底模会影响：</p><ul><li>默认画风：写实、动漫、插画、设计图、摄影感。</li><li>对提示词的理解方式：自然语言、标签、混合写法。</li><li>支持的分辨率：例如 SD1.5 常见 512 系，SDXL 常见 1024 系。</li><li>可用 LoRA：LoRA 通常只能在相近生态里稳定工作。</li><li>图片细节和稳定性：人体、手、文字、背景复杂度都会受影响。</li></ul><p>提示词不能完全替代底模。一个偏写实的模型很难只靠提示词稳定变成纯动画截图风格；一个偏二次元的模型也未必适合真实产品摄影。</p><h2 id="常见底模生态" tabindex="-1">常见底模生态 <a class="header-anchor" href="#常见底模生态" aria-label="Permalink to &quot;常见底模生态&quot;">​</a></h2><h3 id="sd1-5" tabindex="-1">SD1.5 <a class="header-anchor" href="#sd1-5" aria-label="Permalink to &quot;SD1.5&quot;">​</a></h3><p>早期 Stable Diffusion 生态。优点是资源多、显存要求低、插件和教程多。缺点是基础分辨率和画面细节较旧。</p><h3 id="sdxl" tabindex="-1">SDXL <a class="header-anchor" href="#sdxl" aria-label="Permalink to &quot;SDXL&quot;">​</a></h3><p>比 SD1.5 更新的一代 Stable Diffusion 生态。更适合 1024 分辨率，画面结构和细节通常更好。</p><h3 id="pony" tabindex="-1">Pony <a class="header-anchor" href="#pony" aria-label="Permalink to &quot;Pony&quot;">​</a></h3><p>基于 SDXL 生态发展出的二次元/角色向模型体系。常见于角色、动漫、标签式提示词和大量 LoRA 玩法。</p><h3 id="illustrious-noobai" tabindex="-1">Illustrious / NoobAI <a class="header-anchor" href="#illustrious-noobai" aria-label="Permalink to &quot;Illustrious / NoobAI&quot;">​</a></h3><p>偏二次元插画与标签体系的模型生态。资源和 LoRA 多，但不要默认与 Pony 完全兼容。</p><h3 id="flux" tabindex="-1">FLUX <a class="header-anchor" href="#flux" aria-label="Permalink to &quot;FLUX&quot;">​</a></h3><p>新一代图像生成模型生态，通常更擅长自然语言理解、质感和复杂画面。但工作流、模型结构和 LoRA 兼容性与 SDXL 系不同。</p><h3 id="qwen-image-z-image" tabindex="-1">Qwen-Image / Z-Image <a class="header-anchor" href="#qwen-image-z-image" aria-label="Permalink to &quot;Qwen-Image / Z-Image&quot;">​</a></h3><p>偏新一代多模态或图像生成体系，常见特点是语言理解、中文能力、文字渲染或图像编辑能力更强。生态还在快速变化，使用时要看模型卡和工作流说明。</p><h2 id="如何判断-lora-是否适合某个底模" tabindex="-1">如何判断 LoRA 是否适合某个底模 <a class="header-anchor" href="#如何判断-lora-是否适合某个底模" aria-label="Permalink to &quot;如何判断 LoRA 是否适合某个底模&quot;">​</a></h2><p>优先看模型页面的 <code>Base Model</code> 或说明：</p><ul><li>写 SD1.5 的 LoRA，不要默认给 SDXL 用。</li><li>写 SDXL 的 LoRA，不要默认给 FLUX 或 Qwen-Image 用。</li><li>写 Pony / PonyXL 的 LoRA，优先配 Pony 系模型。</li><li>写 FLUX.1 的 LoRA，不要默认配 FLUX.2。</li><li>写 Z-Image 的 LoRA，优先配 Z-Image 系模型。</li></ul><p>判断不清时，先低权重测试，例如 0.3 到 0.6。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>“模型越新越好”：不一定。生态、LoRA、教程和显存需求同样重要。</li><li>“所有 <code>.safetensors</code> 都一样”：不一样。它可能是 checkpoint、LoRA、VAE 或文本编码器。</li><li>“只要名字像就能混用”：不可靠。要看模型结构和训练说明。</li></ul>',29)])])}const m=e(t,[["render",r]]);export{u as __pageData,m as default};
